mapper.select:
select m1.id,m1.table_id,m1.work_id,m1.status,m1.create_time,m1.update_time, m2.id id2,m2.hdr_name,m2.hdr_code,m2.pid,m2.status status2,m2.remark remark2,m2.type type2, m2.serial_num,m2.is_test,m3.id id3,m3.task_id,m3.company_id,m3.time_stamp,m3.data_base, m3.status status3,m3.tran_id,m3.remark remark3,m3.update_time update_time3,m3.create_time create_time3, m3.prohibit_time prohibit_time3,m3.cron,m3.work_untis_name,m3.work_untis_code,m3.type type3,m3.monitoring_events, m3.broadcast_events,m3.sending_broadcast_events, m4.ThirdPartyName as third_party_name,m5.NAME as transformation_name from VzDataQuality.dbo.tb_taskdeployment m1 left join VzDataQuality.dbo.tb_collectiontask m2 on m1.table_id=m2.id left join VzDataQuality.dbo.tb_collectiontimingdata m3 on m1.work_id=m3.id left join VzDataQuality.dbo.ThridParty m4 on m3.company_id=m4.SysId left join VzDataQuality.dbo.r_transformation m5 on m3.tran_id=m5.ID_TRANSFORMATION where m1.status!=2 and m3.status!=2
and m1.table_id=#{map.table_id}
and m1.id=#{map.id}
